// src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom'; // Importando Routes e Route
import Navbar from './components/Navbar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Calendar from './components/Calendar'; // Importa o calendário
import Atendimento from './components/Gestao/Atendimento'; // Importar os componentes de cada página
import Pessoa from './components/Gestao/Pessoa';
import Workflow from './components/Gestao/Workflow';
import Timesheet from './components/Gestao/Timesheet';
import RelatoriosGestao from './components/Gestao/Relatorios'; 
import ListaAtividades from './components/Atividades/ListaAtividades'; // Importar atividades
import PainelTarefas from './components/Atividades/PainelTarefas';
import KanbanTarefas from './components/Atividades/KanbanTarefas';
import RelatoriosAtividades from './components/Atividades/Relatorios';
import Processos from './components/Processos/Processos'; // Importar processos
import Intimacoes from './components/Processos/Intimacoes';
import CentralCaptura from './components/Processos/CentralCaptura';
import AndamentosProcessuais from './components/Processos/AndamentosProcessuais';
import RelatoriosProcessos from './components/Processos/Relatorios';
import ReceitasDespesas from './components/Financeiro/ReceitasDespesas'; // Importar financeiro
import ExtratoConta from './components/Financeiro/ExtratoConta';
import Solicitacoes from './components/Financeiro/Solicitacoes';
import IntegracaoReceitas from './components/Financeiro/IntegracaoReceitas';
import RelatoriosFinanceiro from './components/Financeiro/Relatorios';
import Documentos from './components/Documentos/Documentos'; // Importar documentos
import ModelosDocumentos from './components/Documentos/ModelosDocumentos';
import Conexoes from './components/Extensoes/Conexoes'; // Importar extensões
import RelatoriosExtensoes from './components/Extensoes/Relatorios';
import Notificacao from './components/Notificacao'; // Importar notificações
import Configuracoes from './components/Configuracoes'; // Importar configurações
import Ajuda from './components/Ajuda'; // Importar ajuda
import AreaUsuario from './components/AreaUsuario'; // Importar área do usuário
import './App.css'; // Adiciona o arquivo de estilo

const App = () => {
  return (
    <Router>
      <div className="app-container">
        <Navbar />
        <Header />
        <Routes> {/* Adicionando Routes para gerenciar as diferentes rotas */}
          <Route path="/" element={<Dashboard />} /> {/* Rota para Dashboard */}
          <Route path="/gestao/item1" element={<Atendimento />} />
          <Route path="/gestao/item2" element={<Pessoa />} />
          <Route path="/gestao/item3" element={<Workflow />} />
          <Route path="/gestao/item4" element={<Timesheet />} />
          <Route path="/gestao/item5" element={<RelatoriosGestao />} />
          <Route path="/atividades" element={<ListaAtividades />} />
          <Route path="/atividades/item1" element={<ListaAtividades />} />
          <Route path="/atividades/item2" element={<PainelTarefas />} />
          <Route path="/atividades/item3" element={<KanbanTarefas />} />
          <Route path="/atividades/item4" element={<RelatoriosAtividades />} />
          <Route path="/processos" element={<Processos />} />
          <Route path="/processos/item1" element={<Processos />} />
          <Route path="/processos/item2" element={<Intimacoes />} />
          <Route path="/processos/item3" element={<CentralCaptura />} />
          <Route path="/processos/item4" element={<AndamentosProcessuais />} />
          <Route path="/processos/item5" element={<RelatoriosProcessos />} />
          <Route path="/financeiro" element={<ReceitasDespesas />} />
          <Route path="/financeiro/item1" element={<ReceitasDespesas />} />
          <Route path="/financeiro/item2" element={<ExtratoConta />} />
          <Route path="/financeiro/item3" element={<Solicitacoes />} />
          <Route path="/financeiro/item4" element={<IntegracaoReceitas />} />
          <Route path="/financeiro/item5" element={<RelatoriosFinanceiro />} />
          <Route path="/documentos" element={<Documentos />} />
          <Route path="/documentos/item1" element={<Documentos />} />
          <Route path="/documentos/item2" element={<ModelosDocumentos />} />
          <Route path="/extensoes" element={<Conexoes />} />
          <Route path="/extensoes/item1" element={<Conexoes />} />
          <Route path="/extensoes/item2" element={<RelatoriosExtensoes />} />
          <Route path="/notificacao" element={<Notificacao />} />
          <Route path="/configuracoes" element={<Configuracoes />} />
          <Route path="/ajuda" element={<Ajuda />} />
          <Route path="/area_do_usuario" element={<AreaUsuario />} />
          <Route path="/area_do_usuario/item1" element={<AreaUsuario />} />
          <Route path="/area_do_usuario/item2" element={<Configuracoes />} />
          <Route path="/area_do_usuario/item3" element={<AreaUsuario />} />
        </Routes>
        <div className="calendar-container"> {/* Novo container para o calendário */}
          <Calendar />
        </div>
      </div>
    </Router>
  );
};

export default App;
